const tagDescriptions = {
    "Magia": `Os Magos são indivíduos que dedicam suas vidas ao estudo dos mistérios arcanos...`,
    // pode adicionar descrições para grupos de raças também
};



function getColor(cor) {
    const colors = {
        red: "#ef4444", amber: "#f59e0b", yellow: "#eab308", green: "#22c55e",
        blue: "#3b82f6", indigo: "#6366f1", violet: "#a855f7", 
        cyan: "#06b6d4", purple: "#8b5cf6", zinc: "#71717a", stone: "#e5e7eb"
    };
    return colors[cor] || "#fbbf24";
}

function renderGrouped(items, containerId) {
    const container = document.getElementById(containerId);
    container.innerHTML = "";

    const groups = {};
    items.forEach(item => {
        const g = item.grupo || "Outros";
        if (!groups[g]) groups[g] = [];
        groups[g].push(item);
    });

    Object.keys(groups).forEach(groupName => {
        const section = document.createElement('div');
        section.innerHTML = `
            <div onclick="showTagPopup('${groupName}')" class="cursor-pointer mb-8 group">
                <h2 class="text-4xl font-bold text-amber-400 group-hover:text-amber-300 transition">
                    ${groupName}
                </h2>
            </div>
            <div class="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                ${groups[groupName].map(item => `
                    <div onclick="showModal('${item.nome}', '${containerId === "classes-groups" ? 'class' : 'race'}')" 
                         class="bg-gray-900 border-2 rounded-3xl overflow-hidden card cursor-pointer hover:scale-105 transition-all"
                         style="border-color: ${getColor(item.cor)}; box-shadow: 0 0 25px ${getColor(item.cor)}60;">
                        <img src="${item.imagemThumb}" class="w-full h-52 object-cover">
                        <div class="p-6">
                            <h3 class="text-xl font-bold text-amber-400">${item.nome}</h3>
                            <p class="text-gray-400 mt-3">${item.descricao}</p>
                        </div>
                    </div>
                `).join('')}
            </div>
        `;
        container.appendChild(section);
    });
}

function showModal(nome, type) {
    const array = type === 'class' ? classes : races;
    const item = array.find(c => c.nome === nome);
    if (!item) return;

    const content = document.getElementById('modal-content');
    content.innerHTML = `
        <img src="${item.imagemGrande}" class="w-full rounded-2xl mb-6" alt="${item.nome}">
        <h2 class="text-4xl font-bold text-amber-400 mb-4">${item.nome}</h2>
        
        <div class="prose prose-invert max-w-none text-gray-300 leading-relaxed">
            ${item.detalhes}
        </div>

        <button onclick="closeModal()" 
                class="mt-10 w-full bg-gray-700 hover:bg-gray-600 py-4 rounded-2xl text-lg font-medium transition">
            Fechar
        </button>
    `;
    document.getElementById('modal').classList.remove('hidden');
}

function closeModal() {
    document.getElementById('modal').classList.add('hidden');
}

function showTagPopup(tag) {
    const desc = tagDescriptions[tag] || "Descrição em breve.";
    // ... (mantive sua função original de popup)
    const popup = document.createElement('div');
    popup.className = "fixed inset-0 bg-black/90 flex items-center justify-center z-50 p-4";
    popup.innerHTML = `
        <div class="bg-gray-900 rounded-3xl p-10 max-w-3xl w-full max-h-[90vh] overflow-auto border-2" 
             style="border-color: #fbbf24; box-shadow: 0 0 30px #fbbf2480;">
            <h2 class="text-4xl font-bold text-amber-400 mb-6">${tag}</h2>
            <p class="text-gray-300 leading-relaxed whitespace-pre-line text-lg">${desc}</p>
            <button onclick="this.closest('.fixed').remove()" 
                    class="mt-10 w-full bg-amber-500 hover:bg-amber-600 text-black font-bold py-4 rounded-2xl text-xl transition">
                Fechar
            </button>
        </div>
    `;
    document.body.appendChild(popup);
}

// ==================== TABS ====================
function showTab(n) {
    document.querySelectorAll('.tab-content').forEach(tab => tab.classList.add('hidden'));
    document.getElementById(`tab-${n}`).classList.remove('hidden');

    document.querySelectorAll('.tab-btn').forEach(btn => btn.classList.remove('active'));
    document.querySelectorAll('.tab-btn')[n].classList.add('active');
}

// ==================== BUSCA ====================
function setupSearch() {
    const searchClasses = document.getElementById('search-classes');
    const searchRaces = document.getElementById('search-races');

    searchClasses.addEventListener('input', () => {
        const term = searchClasses.value.toLowerCase();
        const filtered = classes.filter(c => 
            c.nome.toLowerCase().includes(term) || 
            c.descricao.toLowerCase().includes(term)
        );
        renderGrouped(filtered, 'classes-groups');
    });

    searchRaces.addEventListener('input', () => {
        const term = searchRaces.value.toLowerCase();
        const filtered = races.filter(r => 
            r.nome.toLowerCase().includes(term) || 
            r.descricao.toLowerCase().includes(term)
        );
        renderGrouped(filtered, 'races-groups');
    });
}

window.onload = () => {
    renderGrouped(classes, 'classes-groups');
    renderGrouped(races, 'races-groups');
    setupSearch();
};